import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import type { AgentId, CliOptions, Manifest } from "../types.ts";

export interface PreflightWarning {
  kind: "policy" | "config-authority" | "info";
  message: string;
}

export async function runPreflight(
  _options: CliOptions,
  _manifest: Manifest,
  _home: string,
  detectedAgents: AgentId[],
): Promise<PreflightWarning[]> {
  const warnings: PreflightWarning[] = [];

  for (const agentId of detectedAgents) {
    const agent = AGENT_REGISTRY_BY_ID[agentId];
    if (!agent) continue;
    if (agent.provenance.skills === "implementation-only") {
      warnings.push({
        kind: "config-authority",
        message: `Agent "${agentId}" skill support is implementation-only: paths are derived from source inspection, not published documentation.`,
      });
    } else if (agent.provenance.skills === "provisional") {
      warnings.push({
        kind: "config-authority",
        message: `Agent "${agentId}" skill support is provisional: behavior has not been independently verified.`,
      });
    }
    if (agent.policyNote) {
      warnings.push({
        kind: "policy",
        message: `Agent "${agentId}": ${agent.policyNote}`,
      });
    }
  }

  return warnings;
}

import nodePath from "node:path";
import { z } from "zod";

const AGENT_IDS = [
  "claude-code",
  "codex",
  "gemini-cli",
  "antigravity",
  "opencode",
  "github-copilot",
] as const;

export { AGENT_IDS };

const SAFE_NAME_RE = /^[a-zA-Z0-9][a-zA-Z0-9._-]*$/;

// Target templates must be rooted at a known placeholder and may only add
// descendant path segments beneath that root. e.g. "{home}/.claude/settings.json"
// is valid, while "{home}/../.ssh/config" is rejected.
const TARGET_TEMPLATE_RE = /^\{(home|appdata|xdg_config)\}(?:[\\/].*)?$/;

// Standalone schema used for type derivation and single-ID validation (e.g. index.ts).
export const AgentIdSchema = z.enum(AGENT_IDS);
export type AgentId = z.output<typeof AgentIdSchema>;

// Used inside SkillEntrySchema.agents so that enum failures embed the received
// value in the message (Zod 4's invalid_value issue omits the received value).
// The .pipe(AgentIdSchema) at the end provides the AgentId output type.
